action.script:
transferItem(to=context.subject.inventory, item=itemID);
if (!context.parentObject.price_hacked) {
    context.subject.money = context.subject.money - gameData.itemTemplate(itemID).price;
}
var item = gameData.itemTemplate(itemID).noun;
sendSensoryEvent(area=context.subject.area.id, phrase="@vendingMachineBuy", item=item);

var originAreaID = context.subject.area.id;
var targetArea = context.parentArea.noun;
sendSensoryEvent(area=set{originAreaID, context.parentArea.id}, phrase=context.parentArea.move_phrase, targetArea=targetArea, dirName=dirName);
setArea(object=context.subject, area=context.parentArea);

var originAreaID = context.subject.area.id;
var targetArea = context.parentArea.noun;
sendSensoryEvent(area=originAreaID, phrase="@moveCorner", targetArea=targetArea);
setArea(object=context.subject, area=context.parentArea);
sendSensoryEvent(area=context.parentArea.id, phrase="moveCorner", detectSelf=false, targetArea=targetArea);

var originAreaID = context.subject.area.id;
var targetArea = context.parentArea.noun;
var originRoomID = context.subject.area.room != null ? context.subject.area.room.id : null;
var targetRoomID = context.parentArea.room != null ? context.parentArea.room.id : null;
var originArea = originRoomID != null && originRoomID != targetRoomID ? context.subject.area.room.noun : context.subject.area.noun;
var door = context.parentObject.noun;
sendSensoryEvent(area=originAreaID, phrase="@moveThrough", targetArea=targetArea, originArea=originArea, door=door);
setArea(object=context.subject, area=context.parentArea);
sendSensoryEvent(area=context.parentArea.id, phrase="moveThroughReverse", detectSelf=false, targetArea=targetArea, originArea=originArea, door=door);

var targetArea = context.parentArea.noun;
var vehicle = context.parentObject.noun;
sendSensoryEvent(phrase="@driveTo", area=set{context.subject.area.id, context.parentArea.id}, targetArea=targetArea, vehicle=vehicle);
setArea(object=context.parentObject, area=context.parentArea);

var targetArea = context.parentArea.noun;
var vehicle = context.parentObject.noun;
sendSensoryEvent(phrase="@driveCorner", area=set{context.subject.area.id, context.parentArea.id}, targetArea=targetArea, vehicle=vehicle);
setArea(object=context.parentObject, area=context.parentArea);
